category_card.content:
.category-card {
    border: 1px solid #ccc;
    padding: 10px;
    margin: 10px 0;
    display: flex;
    justify-content: space-between;
    align-items: center;
}
.category-name {
    font-weight: bold;
}
.category-balance {
    font-size: 1.2em;
}
.category-limit {
    width: 100px;
    height: 20px;
    background-color: #eee;
    position: relative;
}
.category-limit-fill {
    height: 100%;
    background-color: #4caf50;
}
.category-limit-negative {
    background-color: #f44336;
}
.category-limit-zero {
    background-color: #9e9e9e;
}

