when_add_category.content:
document.getElementById('add-category-btn').addEventListener('click', () => {
    const form = document.createElement('form');
    form.innerHTML = `
        <input type="text" id="category-name" placeholder="Category Name">
        <input type="number" id="category-limit" placeholder="Category Limit">
        <button type="submit">Add</button>
    `;
    document.body.appendChild(form);

    form.addEventListener('submit', (e) => {
        e.preventDefault();
        const name = document.getElementById('category-name').value;
        const limit = parseFloat(document.getElementById('category-limit').value);
        if (limit < 0) {
            alert('Category limit cannot be negative');
            return;
        }
        budgetCategories.push({ name, balance: 0, limit });
        updateUI();
        form.remove();
    });
});

