surface_category_card.content:
function renderCategoryCard(category) {
    const card = document.createElement('div');
    card.className = 'category-card';
    card.innerHTML = `
        <div>
            <span class="category-name">${category.name}</span>
            <span class="category-balance" style="color: ${category.balance > 0 ? 'green' : category.balance < 0 ? 'red' : 'gray'}">${category.balance}</span>
        </div>
        <div class="category-limit">
            <div class="category-limit-fill" style="width: ${category.balance / category.limit * 100}%"></div>
        </div>
    `;
    return card;
}

