anchor.content:
function updateUI() {
    const budgetCategoriesSection = document.getElementById('budget-categories');
    budgetCategoriesSection.innerHTML = '';
    budgetCategories.forEach(category => {
        budgetCategoriesSection.appendChild(renderCategoryCard(category));
    });
    validateCategoryLimits();
    totalIncome = budgetCategories.reduce((acc, category) => acc + Math.max(0, category.balance), 0);
    totalExpenses = budgetCategories.reduce((acc, category) => acc + Math.min(0, category.balance), 0);
    document.getElementById('total-income').innerText = `Total Income: $${totalIncome}`;
    document.getElementById('total-expenses').innerText = `Total Expenses: $${totalExpenses}`;
}

